CREATE VIEW `dwd_competitor_data_ai_app_timeline_view` (`product_id` COMMENT "产品id", `date` COMMENT "发布日期", `old_value` COMMENT "更新前老版本号", `Id`, `new_value` COMMENT "新版本号", `event_type` COMMENT "更新类型", `release_note` COMMENT "新版本描述（更新内容）", `release_date` COMMENT "发布日期", `updatetime` COMMENT "更新时间", `inittime` COMMENT "写入时间", `sr_createtime`, `sr_updatetime`, `etl_time`)
COMMENT "app版本信息表" AS (SELECT `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`product_id`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`date`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`old_value`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`Id`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`new_value`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`event_type`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`release_note`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`release_date`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`updatetime`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`inittime`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`sr_createtime`, `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`.`sr_updatetime`, current_timestamp() AS `etl_time`
FROM `ods`.`ods_tidb_sharpengine_bi_data_ai_app_timeline`);
